function a(t){if(t===0)return"0 B";const r=1024,n=["B","KB","MB","GB","TB"],e=Math.floor(Math.log(t)/Math.log(r));return parseFloat((t/Math.pow(r,e)).toFixed(2))+" "+n[e]}function s(t){return t===0?"0 B/s":a(t)+"/s"}function u(t){switch(t){case-1:return"失败";case 0:return"分配中";case 1:return"下载中";case 2:return"已完成";default:return"未知"}}function c(t){switch(t){case-1:return"danger";case 0:return"info";case 1:return"warning";case 2:return"success";default:return""}}export{c as a,s as b,a as f,u as g};
